 455→function renderSubtitle(text) {
 456→  subtitleText.innerHTML = '';
 457→  wordInlinePanel.style.display = 'none';
 458→  for (const w of text.split(/(\s+)/)) {
 459→    if (/^\s+$/.test(w)) { subtitleText.appendChild(document.createTextNode(' ')); continue; }
 460→    const span = document.createElement('span');
 461→    span.className = 'word'; span.textContent = w;
 462→    span.addEventListener('click', (e) => {
 463→      e.stopPropagation();
 464→      videoPlayer.pause();
 465→      const sel = window.getSelection().toString().trim();
 466→      if (sel && sel.includes(' ')) {
 467→        // 选中了短语
 468→        showWordInline(sel);
 469→      } else {
 470→        const clean = cleanWord(w);
 471→        if (clean) showWordInline(clean);
 472→      }
 473→    });
 474→    subtitleText.appendChild(span);
 475→  }
 476→}
