 484→  const btn = document.createElement('button');
 485→  btn.id = 'phraseCollectBtn';
 486→  btn.className = 'btn btn-small phrase-collect-btn';
 487→  btn.textContent = sel.includes(' ') ? '☆ 收藏短语' : '☆ 收藏';
 488→  btn.style.cssText = `position:fixed;left:${e.clientX+5}px;top:${e.clientY-35}px;z-index:5000;`;
 489→  btn.addEventListener('click', async () => {
 490→    await ipcRenderer.invoke('fav-add', sel, currentLang, '', '', currentSentence || '');
 491→    btn.textContent = '★ 已收藏';
 492→    btn.style.color = '#ff0000';
 493→    setTimeout(() => btn.remove(), 800);
 494→  });
 495→  document.body.appendChild(btn);
 496→  setTimeout(() => { if (btn.parentNode) btn.remove(); }, 4000);
 497→});
