 837→async function loadVocabList() {
 838→  allVocabList = await ipcRenderer.invoke('fav-list');
 839→  const boxes = await ipcRenderer.invoke('fav-list-boxes');
 840→  selectedWordIds.clear();
 841→  updateSelImageBtn();
 842→
 843→  // 渲染箱子标签
 844→  const tabs = document.getElementById('vocabBoxTabs');
 845→  tabs.innerHTML = '';
 846→  const allCount = allVocabList.length;
 847→  const unboxedCount = allVocabList.filter(w => !w.box).length;
 848→
 849→  const addTab = (label, box, count) => {
 850→    const tab = document.createElement('span');
 851→    tab.className = 'vocab-box-tab' + (currentBox === box ? ' active' : '');
 852→    tab.innerHTML = `${label}<span class="tab-count">${count}</span>`;
 853→    tab.addEventListener('click', () => { currentBox = box; loadVocabList(); });
 854→    // 拖放目标
 855→    tab.addEventListener('dragover', (e) => { e.preventDefault(); tab.style.transform = 'scale(1.1)'; });
 856→    tab.addEventListener('dragleave', () => { tab.style.transform = ''; });
 857→    tab.addEventListener('drop', async (e) => {
 858→      e.preventDefault(); tab.style.transform = '';
 859→      const wordId = e.dataTransfer.getData('text/plain');
 860→      if (wordId) {
 861→        // 如果有多选，批量移动
 862→        const ids = selectedWordIds.size > 0 ? [...selectedWordIds] : [parseInt(wordId)];
 863→        await ipcRenderer.invoke('fav-batch-set-box', ids, box);
 864→        loadVocabList();
 865→      }
 866→    });
 867→    tabs.appendChild(tab);
 868→  };
 869→
 870→  addTab('📋 全部', '', allCount);
 871→  addTab('📥 未分类', '__unboxed__', unboxedCount);
 872→  for (const b of boxes) {
 873→    const cnt = allVocabList.filter(w => w.box === b).length;
 874→    addTab('📦 ' + b, b, cnt);
 875→  }
 876→
 877→  // 过滤当前箱子
 878→  let filtered = allVocabList;
 879→  if (currentBox === '__unboxed__') filtered = allVocabList.filter(w => !w.box);
 880→  else if (currentBox) filtered = allVocabList.filter(w => w.box === currentBox);
