 893→      <div class="vocab-card-word" style="margin-left:22px">${item.word}</div>
 894→      <div class="vocab-card-phonetic">${item.phonetic || ''}</div>
 895→      <div class="vocab-card-trans">${item.translation || ''}</div>
 896→      ${item.box ? '<div style="font-size:10px;color:var(--accent3);margin-top:4px">📦 ' + item.box + '</div>' : ''}
 897→      <button class="vocab-card-del" title="删除">✕</button>`;
 898→
 899→    // 拖拽
 900→    card.addEventListener('dragstart', (e) => {
 901→      e.dataTransfer.setData('text/plain', String(item.id));
 902→      card.classList.add('dragging');
 903→    });
 904→    card.addEventListener('dragend', () => card.classList.remove('dragging'));
 905→
 906→    // 多选
 907→    const chk = card.querySelector('.vocab-check');
 908→    chk.addEventListener('change', () => {
 909→      if (chk.checked) { selectedWordIds.add(item.id); card.classList.add('selected'); }
 910→      else { selectedWordIds.delete(item.id); card.classList.remove('selected'); }
 911→      updateSelImageBtn();
