1089→      drawFallbackBg(ctx, W, H, title);
1090→    }
1091→  } else {
1092→    drawFallbackBg(ctx, W, H, title);
1093→  }
1094→
1095→  // 半透明遮罩让标注更清晰
1096→  const grad = ctx.createLinearGradient(0, 0, 0, H);
1097→  grad.addColorStop(0, 'rgba(0,0,0,0.15)');
1098→  grad.addColorStop(0.4, 'rgba(0,0,0,0.05)');
1099→  grad.addColorStop(0.6, 'rgba(0,0,0,0.1)');
1100→  grad.addColorStop(1, 'rgba(0,0,0,0.55)');
1101→  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);
1102→
1103→  // 顶部标题
1104→  ctx.font = 'bold 24px Microsoft YaHei UI';
1105→  const tw = ctx.measureText('📚 ' + title).width + 40;
1106→  ctx.fillStyle = 'rgba(91,122,94,0.9)';
1107→  rrect(ctx, 20, 16, tw, 48, 24); ctx.fill();
1108→  ctx.fillStyle = '#fff'; ctx.textAlign = 'left';
