1110→
1111→  // 词汇标注卡片 - 散布在画面中
1112→  const n = wordDetails.length;
1113→  const cols = Math.min(3, n);
1114→  const rows = Math.ceil(n / cols);
1115→  const cardW = 300, cardH = 62, gapX = 16, gapY = 14;
1116→  const gridW = cols * (cardW + gapX) - gapX;
1117→  const gridH = rows * (cardH + gapY) - gapY;
1118→  const ox = (W - gridW) / 2;
1119→  const oy = H - gridH - 40;
1120→
1121→  for (let i = 0; i < n; i++) {
1122→    const wd = wordDetails[i];
1123→    const col = i % cols, row = Math.floor(i / cols);
1124→    const x = ox + col * (cardW + gapX);
1125→    const y = oy + row * (cardH + gapY);
1126→
1127→    // 卡片背景 - 白色圆角带阴影
1128→    ctx.shadowColor = 'rgba(0,0,0,0.3)'; ctx.shadowBlur = 10; ctx.shadowOffsetY = 3;
1129→    ctx.fillStyle = 'rgba(255,255,255,0.92)';
1130→    rrect(ctx, x, y, cardW, cardH, 12); ctx.fill();
1131→    ctx.shadowColor = 'transparent'; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;
1132→
1133→    // 左侧色条
1134→    ctx.fillStyle = '#5b7a5e';
1135→    rrect(ctx, x, y, 6, cardH, 3); ctx.fill();
1136→
1137→    // 序号圆
1138→    ctx.fillStyle = '#5b7a5e';
1139→    ctx.beginPath(); ctx.arc(x + 22, y + 20, 10, 0, Math.PI * 2); ctx.fill();
1140→    ctx.fillStyle = '#fff'; ctx.font = 'bold 11px Microsoft YaHei UI'; ctx.textAlign = 'center';
1141→    ctx.fillText(String(i + 1), x + 22, y + 24);
1142→
1143→    // 单词
1144→    ctx.fillStyle = '#1a1a1a'; ctx.font = 'bold 20px Microsoft YaHei UI'; ctx.textAlign = 'left';
1145→    ctx.fillText(wd.word, x + 40, y + 26);
1146→
1147→    // 中文释义
1148→    if (wd.translation) {
1149→      ctx.fillStyle = '#5b7a5e'; ctx.font = '14px Microsoft YaHei UI';
1150→      ctx.fillText(wd.translation.slice(0, 24), x + 40, y + 50);
1151→    }
