1154→  // 底部水印
1155→  ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.font = '11px Microsoft YaHei UI'; ctx.textAlign = 'center';
1156→  ctx.fillText('多语言视频学习 · 词汇场景图', W / 2, H - 10);
